import React from 'react'

export default function About() {
  return (
    <div style={style.about}>
      <h1>About</h1>
      <p>Created by Madiantara Teja | Coba React</p>
    </div>
  )
}

const style = {
  about: {
    padding: "50px",
    margin: "auto",
    textAlign: "center",
    marginTop: "25px"
  }
}
