import React, { Component } from 'react';
import PropTypes from 'prop-types';

const styles = {
 container: {backgroundColor: "#f4f4f4"},
 text: {
  textTransform: "uppercase", 
  padding: "10px", 
  backgroundColor: "#f4f4f4",
  borderBottom: "1px dotted red"
  },
  button: {
   backgroundColor: "darkred",
   color: "white",
   fontSize: ".5rem",
   padding: "5px 7.4px",
   border: "none",
   borderRadius: "50%",
   float: "right",
   marginRight: "5px",
   cursor: "pointer"
  }
 } // end styles

class TodoItem extends Component {
 getProp() {return this.props;};
 getState() {return this.state;};
 getStyle = () => {
  return ({
   textDecoration: this.props.todo.completed ? "line-through" : "none" 
  });
 };

 render() {
  let merged = {...this.getStyle(), ...styles.text};
  let {id, title} = this.props.todo
  return (
   <div style={styles.container}>
     <h3 style={merged}>
     <input type="checkbox" onChange={this.props.markCompleted.bind(this, id)}></input>{' '}
     {title}
     <button title="delete" style={styles.button} onClick={this.props.delItem.bind(this, id)}>x</button>
     </h3>
   </div>
  );
 };
};

TodoItem.propTypes = {
 todo: PropTypes.object.isRequired
}

export default TodoItem;